        uint256 totalVal = _sharesToTokens(vault.balanceOf(address(this)));
        require(_amount <= totalVal * s.maxWithdrawPercent / 10000,
            "YearnVaultAdapterWithIndirection: withdrawal amount exceeds limit");

        // Anti‑reentrancy lock
        require(!s.locked, "YearnVaultAdapterWithIndirection: reentrant call");
        s.locked = true;

        vault.safeTransfer(_recipient, _tokensToShares(_amount));

