// 补丁1：在 _getWrappedTokenRate() 添加输入验证
function _getWrappedTokenRate() internal view override returns (uint256) {
    uint256 rate = _lendingPool.getReserveNormalizedIncome(getMainToken());
    // 新增：边界检查，确保Aave返回值在合理范围内（约 1e27）
+   require(rate >= 0.9e27 && rate <= 1.1e27, "Invalid normalized income from Aave");
    return rate / 10**9;
}

// 补丁2：在 getRate() 函数添加输出验证（或输入验证）
function getRate() external view override returns (uint256) {
    // ... 原有计算逻辑 ...
    uint256 calculatedRate = totalBalance.divUp(_getApproximateVirtualSupply(balances[_bptIndex]));
    // 新增：最终汇率合理性检查
+   require(calculatedRate >= 0.5e18 && calculatedRate <= 5e18, "Invalid rate");
    return calculatedRate;
}
```

