// 增强版fallback函数，添加多层验证
fallback() external payable {
    require(!emergencyPause, "Contract paused");

    bytes4 selector = bytes4(msg.data);

    // 1. 敏感函数选择器验证
    if (selector == 0x1163b2b0) { // sweepETH
        require(msg.data.length == 4 || msg.data.length == 36, "Invalid calldata length for sweepETH");
        if (msg.data.length == 36) {
            address recipient = abi.decode(msg.data[4:], (address));
            require(isValidRecipient(recipient), "Invalid recipient address");
            require(!isBlacklistedAddress(recipient), "Recipient is blacklisted");
        }
    }

    if (selector == 0x582515c7) { // sweepERC20
        require(msg.data.length == 68, "Invalid calldata length for sweepERC20");
        (address token, address recipient) = abi.decode(msg.data[4:], (address, address));
        require(isValidToken(token), "Invalid token address");
        require(isValidRecipient(recipient), "Invalid recipient address");
        require(!isBlacklistedAddress(recipient), "Recipient is blacklisted");
    }

    // 2. 逻辑合约权限验证
    address logic = _implementation;
    require(logic != address(0), "Logic contract not set");
    require(isAuthorizedLogic(logic), "Unauthorized logic contract");

    // 3. 执行DELEGATECALL
    (bool success, ) = logic.delegatecall(msg.data);
    require(success, "Delegatecall failed");
}
