contract MinterProxyV2 is Controller, ReentrancyGuard {
    // --- Patch Head Begin (Mode A: Solidity >= 0.6.0) ---
    struct __PatchState {
        bool initialized;
        mapping(bytes4 => bool) allowedSelectors;
