    function __patchStorage() internal pure returns (__PatchState storage s) {
        bytes32 slot = keccak256("patch.MinterProxyV2.storage");
        assembly {
            s.slot := slot
        }
    }

    function __ensurePatchInit() internal {
        __PatchState storage s = __patchStorage();
        if (!s.initialized) {
            // Initialize with critical function selectors to prevent authorization abuse
            s.allowedSelectors[0x7ff36ab5] = true; // swapExactETHForTokens (Uniswap V2)
            s.allowedSelectors[0x38ed1739] = true; // swapExactTokensForTokens (Uniswap V2)
            s.allowedSelectors[0x8803dbee] = true; // swapTokensForExactTokens (Uniswap V2)
            s.allowedSelectors[0x5c11d795] = true; // swapExactTokensForTokensSupportingFeeOnTransferTokens
            s.allowedSelectors[0xfb3bdb41] = true; // swapETHForExactTokens (Uniswap V2)
            s.allowedSelectors[0x4a25d94a] = true; // exactInputSingle (Uniswap V3)
            s.allowedSelectors[0xc04b8d59] = true; // exactInput (Uniswap V3)
            s.initialized = true;
        }
    }

    // Owner-only functions to manage allowed selectors
    function patchAddAllowedSelector(bytes4 selector) external onlyOwner {
        __ensurePatchInit();
        __PatchState storage s = __patchStorage();
        s.allowedSelectors[selector] = true;
    }

    function patchRemoveAllowedSelector(bytes4 selector) external onlyOwner {
        __ensurePatchInit();
        __PatchState storage s = __patchStorage();
        s.allowedSelectors[selector] = false;
    }

    // Internal helper to validate callData
    function _validateCallData(bytes calldata callData) internal view {
        require(callData.length >= 4, "MP: callData too short");
        bytes4 funcSelector = bytes4(callData);
        __PatchState storage s = __patchStorage();
        require(s.allowedSelectors[funcSelector], "MP: function not allowed");

        // Additional safety: explicitly block dangerous selectors even if they were accidentally allowed
        require(funcSelector != 0x23b872dd, "MP: transferFrom not allowed"); // transferFrom
        require(funcSelector != 0x095ea7b3, "MP: approve not allowed"); // approve
        require(funcSelector != 0xa9059cbb, "MP: transfer not allowed"); // transfer
    }
