    }

    function setDeviationThreshold(uint256 newThreshold) external {
        require(msg.sender == address(controller), "Only controller can set threshold");
        __PatchState storage s = __patchStorage();
        s.deviationThreshold = newThreshold;
    }

    function _getPrice(address asset) internal view returns (uint256) {
        __PatchState storage s = __patchStorage();
        require(s.oracle != address(0), "Oracle not set");

        (bool success, bytes memory data) = s.oracle.staticcall(
            abi.encodeWithSignature("getPrice(address)", asset)
        );
        require(success, "Price fetch failed");
        return abi.decode(data, (uint256));
    }

    function _isWithinTolerance(uint256 a, uint256 b, uint256 tolerance) internal pure returns (bool) {
        if (a == b) return true;
        if (a == 0 || b == 0) return false;

        uint256 diff = a > b ? a - b : b - a;
        uint256 max = a > b ? a : b;
        // tolerance is in basis points (1/10000)
        return diff * 10000 <= max * tolerance;
    }
