        require(power > 0, "Validator has zero stake");

        // 修复2: 恢复并执行权益权重检查（例如要求单个验证者权益占比达标）
        // require(power * 100 >= totalStaked * minValidatorPowerRatio, "Validator power too low");

        signedPower += power;

        // 修复3: （可选）签名者去重逻辑
    }

    // 修复4: 要求累计签名权益满足总权益阈值（如66%）
    require(signedPower * 100 >= totalStaked * requiredPowerPercentage, "Insufficient signed power"); // 验证中触发的revert
    require(i >= requiredSignatures, "not enough signatures");
}
```
**关键修复**：恢复了权益权重检查，并禁止零余额验证者参与。

**2. 治理与参数安全加固：**
*   为 `_setCollateralFactor` 等关键函数添加**渐进式调整限制**和**激活时间锁**，防止从0到极值的突变被原子化利用。
*   示例：对抵押因子从0激活的情况，设置一个较低的初始上限和强制延迟生效期。

**3. StakingBank合约增强：**
*   设定**最小质押金额** (`MIN_STAKE_AMOUNT`)。
*   引入**质押锁定期** (`STAKE_LOCK_PERIOD`) 防止快速撤资。
*   增加**定期清理**零余额或不活跃验证者的功能。

### 4.2 验证结果

根据 `<Verification_Evidence>`，修复方案的有效性已得到实战验证：

*   **模拟执行结果**：在部署了上述修复补丁（特别是恢复了 `submit` 函数权益检查）的環境中，**原攻击交易被完全拦截**。
*   **拦截位置**：交易在执行至Trace节点 **[21986]**（即漏洞函数 `submit`）时发生回滚 (`REVERT`)。
*   **回滚信息**：错误信息为 `"not enough power was gathered"`。此信息直接对应于补丁中新增的权益检查逻辑 `require(signedPower * 100 >= totalStaked * requiredPowerPercentage, ...)`。由于攻击者使用的四个验证者 `power` 均为0，无法满足任何正数的权益阈值要求。
*   **攻击效果**：攻击交易全程无法执行，**攻击者最终利润为 0 USDT**。所有后续的借贷、铸造、兑换操作均未发生。

**结论**：补丁成功定位并修复了根本漏洞。验证结果表明，恢复预言机签名验证中的权益权重检查，是阻止此类“零权益签名攻击”的有效且必要措施。修复后的系统能够有效防御基于同一漏洞原理的未来攻击变种。

