    uint amountIn,
    uint amountOutMin,
    address[] calldata path,
    address to,
    uint deadline
) external virtual override ensure(deadline) {
    // 修复1: 禁止零滑点设置
    require(amountOutMin > 0, 'UniswapV2: ZERO_SLIPPAGE_NOT_ALLOWED');

