function swapAndStartBridgeTokensViaCBridge(...) external payable {
    // ... 原有逻辑 ...

    // +++ 新增预验证 +++
    require(_swapData.length > 0, "_swapData cannot be empty");
    require(_swapData.length <= MAX_SWAP_DATA_LENGTH, "_swapData too long"); // 例如 MAX=20

    for (uint256 i = 0; i < _swapData.length; i++) {
        LibSwap.SwapData memory item = _swapData[i];
        // 禁止sendingAssetId和receivingAssetId同时为零地址的无效元素
        if (item.sendingAssetId == address(0) && item.receivingAssetId == address(0)) {
            require(item.fromAmount == 0, "Invalid swap with zero addresses");
            require(item.callData.length == 0, "Invalid callData for zero address swap");
            continue; // 跳过此无效元素
        }
        require(
            item.sendingAssetId != address(0) || item.receivingAssetId != address(0),
            "At least one token address must be valid"
        );
    }
    // --- 新增预验证 ---

    LibSwap.swap(_lifiData.transactionId, _swapData);
    // ... 后续桥接逻辑 ...
}
```

**补丁2：修复 `LibSwap.swap()` 核心逻辑漏洞**
```solidity
function swap(bytes32 transactionId, Calldata[] memory swapData) internal {
    for (uint256 i = 0; i < swapData.length; i++) {
        Calldata memory current = swapData[i];
        address sendingAssetId = current.sendingAssetId;
        address receivingAssetId = current.receivingAssetId;
        uint256 swapAmount = current.fromAmount;

        if (sendingAssetId == address(0)) {
            // +++ 严格修复：当sendingAssetId为零地址时，必须满足以下所有条件 +++
            require(receivingAssetId == address(0), "Invalid swap data for zero address sendingAssetId");
            require(swapAmount == 0, "Invalid swap amount for zero address sendingAssetId");
            require(current.callData.length == 0, "Cannot execute callData with zero address sendingAssetId");
            // 修复后：不执行任何操作，仅记录或跳过
            emit SkippedZeroAddressSwap(transactionId, i);
            // --- 修复结束 ---
        } else {
            // 正常的交换逻辑（需额外增加callTo地址白名单校验）
            require(allowedDexContracts[current.callTo], "callTo not in allowed DEX list");
            require(swapAmount > 0, "swapAmount must be > 0");
            require(receivingAssetId != address(0), "receivingAssetId cannot be zero address");
            // ... 执行安全交换 ...
        }
    }
}
```

### **4.2 修复验证结果**

根据 `<Verification_Evidence>` 提供的实战验证反馈：

1.  **防护效果**：应用了**补丁1（数组长度限制）** 的合约成功拦截了原始攻击的重放。攻击交易在初始阶段即被回滚，错误信息清晰指出 `_swapData` 数组过长。
2.  **攻击结果**：在补丁防护下，**攻击者利润为 0 USD**。所有38笔恶意 `transferFrom` 调用均未发生，受害者的资产未被转移。
3.  **结论**：补丁验证成功，确认了以下两点：
    *   我们对攻击向量的定位（超长恶意 `_swapData` 数组）是精确的。
    *   在合约入口处实施严格的输入验证是防御此类攻击的有效且必要的手段。

**综合建议**：尽管入口验证补丁已能防御本次特定攻击，但为了彻底根除隐患，防止攻击者变换手法（例如使用长度小于20但包含恶意元素的数组），**必须同步应用补丁2，修复 `LibSwap.swap()` 函数的核心逻辑缺陷**。两者结合构成纵深防御体系。

