    require(aggregator != address(0), "Invalid aggregator");
    require(owner != address(0), "Invalid owner");
    require(admin != address(0), "Invalid admin");

    store_c = aggregator;
    unresolved_fc931277 = owner;
    unresolved_b784aa21 = admin;

