```solidity
// 修复方案：统一基于当前 PROPHET 余额进行计算和调整
function updateBalance(address account) external {
    // 统一基准：当前 PROPHET 实际余额
    uint256 prophetBalance = IERC20(PROPHET_TOKEN).balanceOf(account);
    uint256 expectedDividendBalance = prophetBalance * 95 / 100; // 95%净额对应

    uint256 currentDividendBalance = _balances[account];

    if (expectedDividendBalance > currentDividendBalance) {
        // 铸造不足部分
        uint256 mintAmount = expectedDividendBalance - currentDividendBalance;
        _balances[account] = expectedDividendBalance;
        totalSupply += mintAmount;
        emit Transfer(address(0), account, mintAmount);
    } else if (expectedDividendBalance < currentDividendBalance) {
        // 销毁超额部分
        uint256 burnAmount = currentDividendBalance - expectedDividendBalance;
        _balances[account] = expectedDividendBalance;
        totalSupply -= burnAmount;
        emit Transfer(account, address(0), burnAmount);
