    // ... 前置代码 ...
    (address swapRouter, address allowanceTarget, bytes memory data) = abi.decode(swapData, (address, address, bytes));

    // +++ 修复点1：验证swapRouter为可信的DEX路由器 +++
    require(isValidSwapRouter(swapRouter), "Invalid swap router");

    // +++ 修复点2：验证data为合法的swap调用（示例：检查函数选择器） +++
    bytes4 funcSelector = bytes4(data);
    require(isAllowedFunction(funcSelector), "Unsupported function call");

    // ... 后续执行代码 ...
}

// 辅助验证函数
function isValidSwapRouter(address router) internal view returns (bool) {
    // 实现可信路由器白名单逻辑
}
function isAllowedFunction(bytes4 selector) internal pure returns (bool) {
    // 实现允许的函数选择器白名单，并排除transferFrom等危险函数
}
```

### 验证结果
根据 `Verification_Evidence`，部署上述补丁逻辑后，对原攻击交易进行了重放测试：
- **执行状态**：交易 **`REVERT`**。
- **攻击者利润**：**0 美元**。重放报告显示无任何余额变化。
- **根本原因准确度**：被评估为 **`HIGH`**。

**结论**：补丁成功修复了漏洞。新添加的验证逻辑在攻击者尝试利用 `_swap` 函数执行恶意 `transferFrom` 调用时，由于 `swapRouter`（代币地址）不在白名单内或 `transferFrom` 的函数选择器被黑名单，触发了 `require` 语句的回滚，从而**完全阻断了资金盗取路径**。这从实战角度最终验证了本次故障的根因分析是完全正确的。

