    bytes32 constant _SLOT_OWNER = keccak256("patch.SimplePriceOracle.owner");

    // 2. Generic Utils (Type-Based)
    function _pSetBool(bytes32 s, bool v) internal { assembly { sstore(s, v) } }
    function _pGetBool(bytes32 s) internal view returns (bool v) { assembly { v := sload(s) } }

    function _pSetAddress(bytes32 s, address v) internal { assembly { sstore(s, v) } }
    function _pGetAddress(bytes32 s) internal view returns (address v) { assembly { v := sload(s) } }

    // 3. Init Logic
    function __ensurePatchInit() internal {
        if (!_pGetBool(_SLOT_INIT)) {
            _pSetBool(_SLOT_INIT, true);
            // Initialize owner to the contract deployer (can be changed later)
            // Note: In patch environment, we cannot know original deployer, so set to contract itself initially
            // Ownership must be transferred to the protocol admin after patch deployment
            _pSetAddress(_SLOT_OWNER, address(this));
        }
    }

    // 4. Access Control Modifiers
    modifier onlyOwner() {
        __ensurePatchInit();
        require(_pGetAddress(_SLOT_OWNER) == msg.sender, "Only owner can call");
        _;
