*   **目的**：实现攻击利润的最终提取和变现，形成完整的攻击闭环。攻击合约内剩余的 885+ ETH 用于支撑这些后续操作的 Gas 成本。

---

### **4. 修复与验证 (Mitigation & Verification)**

#### **4.1 核心修复策略与代码**

修复的核心思路是**将奖励计算的基础从“代币数量”纠正为“代币价值”**，并在质押入口设置价值门槛。

**主要补丁代码片段（摘自 `<Fix_Strategy>`）:**

1.  **在 `calculateEarned` 中引入价值计算与验证**：
    ```solidity
    // 新增：价格预言机接口和状态变量
    interface IPriceOracle { function getPrice(address token) external view returns (uint256); }
    address public priceOracle;
    uint256 public constant MIN_STAKE_VALUE_USD = 100 * 10**8; // $100

    function calculateEarned(uint256 _stakingId, uint256 _stakeIndex) public view returns (uint256) {
        // ... 获取_staking和plan数据 ...
        uint256 stakedTime = currentTime - _staking.stakeAt;

        // --- 修复逻辑 ---
        require(priceOracle != address(0), "Price oracle not set");
        uint256 tokenPrice = IPriceOracle(priceOracle).getPrice(stakingToken); // 获取USD价格
        uint256 stakedValue = _staking.amount.mul(tokenPrice).div(10**18); // 计算质押总价值
        require(stakedValue >= MIN_STAKE_VALUE_USD, "Stake value below minimum"); // 价值门槛
        uint256 earned = stakedValue.mul(plan.apr).mul(stakedTime).div(365 days).div(100); // 基于价值计算奖励
        // --- 修复结束 ---

        return earned;
    }
    ```

2.  **在 `stake` 函数入口添加前置价值校验**：
    ```solidity
    function stake(uint256 _stakingId, uint256 _amount) public nonReentrant {
        // ... 原有参数检查 ...
        // 新增质押价值验证
        require(priceOracle != address(0), "Price oracle not set");
        uint256 tokenPrice = IPriceOracle(priceOracle).getPrice(stakingToken);
        uint256 stakeValue = _amount.mul(tokenPrice).div(10**18);
        require(stakeValue >= MIN_STAKE_VALUE_USD, "Stake value below minimum requirement");
